196	export function evaluateViewFilters(
197	  element: Element,
198	  filters: ViewFilter[],
199	): {
200	  visible: boolean;
201	  lineColor?: string | null;
202	  lineWeightFactor?: number;
203	  fillColor?: string | null;
204	} {
205	  let visible = true;
206	  let lineColor: string | null | undefined;
207	  let lineWeightFactor: number | undefined;
208	  let fillColor: string | null | undefined;
209	
210	  for (const filter of filters) {
211	    const matches = filter.rules.every((rule) => {
212	      const val = (element as Record<string, unknown>)[rule.field];
213	      const strVal = val != null ? String(val) : '';
214	      switch (rule.operator) {
215	        case 'equals':
216	          return strVal === rule.value;
217	        case 'not-equals':
218	          return strVal !== rule.value;
219	        case 'contains':
220	          return strVal.includes(rule.value);
221	        case 'not-contains':
222	          return !strVal.includes(rule.value);
223	        default:
224	          return false;
225	      }
226	    });
227	    if (matches) {
228	      if (filter.override.visible === false) visible = false;
229	      if (filter.override.projection?.lineColor !== undefined)
230	        lineColor = filter.override.projection.lineColor;
231	      if (filter.override.projection?.lineWeightFactor != null)
232	        lineWeightFactor = filter.override.projection.lineWeightFactor;
233	      if (filter.override.projection?.fillColor !== undefined)
234	        fillColor = filter.override.projection.fillColor;
235	    }
236	  }
237	  return { visible, lineColor, lineWeightFactor, fillColor };
238	}
239	```
