36	function coerceViolation(v: unknown): Violation {
37	  const vv = v as Record<string, unknown>;
38	  const ruleId =
39	    typeof vv.ruleId === 'string' ? vv.ruleId : typeof vv.rule_id === 'string' ? vv.rule_id : '';
40	  const sev = vv.severity as string | undefined;
41	  const severity =
42	    sev === 'error' || sev === 'warning' || sev === 'info' ? sev : ('warning' as const);
43	  const elementIdsRaw = vv.elementIds ?? vv.element_ids;
44	  const elementIds =
45	    Array.isArray(elementIdsRaw) && elementIdsRaw.every((x) => typeof x === 'string')
46	      ? elementIdsRaw
47	      : [];
48	  const message = typeof vv.message === 'string' ? vv.message : '';
49	  const blocking = typeof vv.blocking === 'boolean' ? vv.blocking : undefined;
50	  const disciplineRaw = vv.discipline ?? vv.Discipline;
51	  const discipline =
52	    typeof disciplineRaw === 'string' && disciplineRaw.length ? disciplineRaw : undefined;
53	  const qf = vv.quickFixCommand ?? vv.quick_fix_command;
54	
55	  const quickFixCommand =
56	    qf !== undefined && qf !== null && typeof qf === 'object'
57	      ? (qf as Record<string, unknown>)
58	      : null;
59	
60	  return {
61	    ruleId,
62	    severity: severity as Violation['severity'],
63	    message,
64	    elementIds,
65	
66	    ...(blocking !== undefined ? { blocking } : {}),
67	
68	    ...(discipline !== undefined ? { discipline } : {}),
69	
70	    ...(quickFixCommand ? { quickFixCommand } : {}),
71	  };
72	}
73	
74	function coerceXY(raw: Record<string, unknown>): { xMm: number; yMm: number } {
75	  return {
76	    xMm: Number(raw.xMm ?? raw.x_mm ?? 0),
77	    yMm: Number(raw.yMm ?? raw.y_mm ?? 0),
78	  };
79	}
80	
81	function coerceXYZ(raw: Record<string, unknown>): { xMm: number; yMm: number; zMm: number } {
82	  return {
83	    xMm: Number(raw.xMm ?? raw.x_mm ?? 0),
84	    yMm: Number(raw.yMm ?? raw.y_mm ?? 0),
85	    zMm: Number(raw.zMm ?? raw.z_mm ?? 0),
86	  };
87	}
88	
89	const _EVIDENCE_REF_KINDS = new Set<EvidenceRefKind>([
90	  'sheet',
91	  'viewpoint',
92	  'plan_view',
93	  'section_cut',
94	  'deterministic_png',
95	]);
96	
97	function coerceEvidenceRefs(rawUnknown: unknown): EvidenceRef[] {
98	  if (!Array.isArray(rawUnknown)) return [];
99	  const refs: EvidenceRef[] = [];
100	  for (const item of rawUnknown) {
101	    if (typeof item !== 'object' || item === null) continue;
102	    const o = item as Record<string, unknown>;
103	    const kindRaw = o.kind;
104	    if (typeof kindRaw !== 'string' || !_EVIDENCE_REF_KINDS.has(kindRaw as EvidenceRefKind)) {
105	      continue;
106	    }
107	    const kind = kindRaw as EvidenceRefKind;
108	    const sheetId =
109	      typeof (o.sheetId ?? o.sheet_id) === 'string' ? String(o.sheetId ?? o.sheet_id) : undefined;
110	    const viewpointId =
111	      typeof (o.viewpointId ?? o.viewpoint_id) === 'string'
112	        ? String(o.viewpointId ?? o.viewpoint_id)
113	        : undefined;
114	    const planViewId =
115	      typeof (o.planViewId ?? o.plan_view_id) === 'string'
116	        ? String(o.planViewId ?? o.plan_view_id)
117	        : undefined;
118	    const sectionCutId =
119	      typeof (o.sectionCutId ?? o.section_cut_id) === 'string'
120	        ? String(o.sectionCutId ?? o.section_cut_id)
121	        : undefined;
122	    const pngBasename =
123	      typeof (o.pngBasename ?? o.png_basename) === 'string'
124	        ? String(o.pngBasename ?? o.png_basename)
125	        : undefined;
126	    refs.push({
127	      kind,
128	      ...(sheetId !== undefined ? { sheetId } : {}),
129	      ...(viewpointId !== undefined ? { viewpointId } : {}),
130	      ...(planViewId !== undefined ? { planViewId } : {}),
131	      ...(sectionCutId !== undefined ? { sectionCutId } : {}),
132	      ...(pngBasename !== undefined ? { pngBasename } : {}),
133	    });
134	  }
135	  refs.sort((a, b) => {
136	    const ak = `${a.kind}|${a.sheetId ?? ''}|${a.viewpointId ?? ''}|${a.planViewId ?? ''}|${a.sectionCutId ?? ''}|${a.pngBasename ?? ''}`;
137	    const bk = `${b.kind}|${b.sheetId ?? ''}|${b.viewpointId ?? ''}|${b.planViewId ?? ''}|${b.sectionCutId ?? ''}|${b.pngBasename ?? ''}`;
138	    return ak.localeCompare(bk);
139	  });
140	  return refs;
141	}
142	
143	function readPlanViewBoolOverride(raw: unknown): boolean | undefined {
144	  if (raw === null || raw === undefined) return undefined;
145	  if (typeof raw === 'boolean') return raw;
146	  if (typeof raw === 'string') {
147	    const s = raw.trim().toLowerCase();
148	    if (s === '') return undefined;
149	    if (s === 'true' || s === '1') return true;
150	    if (s === 'false' || s === '0') return false;
151	  }
152	  return undefined;
