1307	    mergeComment: (c) =>
1308	      set(() => {
1309	        const nx = [...get().comments.filter((x) => x.id !== c.id), c].sort((a, b) =>
1310	          String(b.createdAt ?? '').localeCompare(String(a.createdAt ?? '')),
1311	        );
1312	
1313	        return { comments: nx };
1314	      }),
1315	
1316	    setPlanHud: (mm) => set({ planHudMm: mm }),
1317	
1318	    setBuildingPreset: (preset) =>
1319	      set(() => {
1320	        try {
1321	          localStorage.setItem('bim.buildingPreset', preset);
1322	        } catch {
1323	          /* noop */
1324	        }
1325	        return { buildingPreset: preset };
1326	      }),
1327	
1328	    setWorkspaceLayoutPreset: (preset) =>
1329	      set(() => {
1330	        try {
1331	          localStorage.setItem('bim.workspaceLayout', preset);
1332	        } catch {
1333	          /* noop */
1334	        }
1335	        return { workspaceLayoutPreset: preset };
1336	      }),
1337	
1338	    setPerspectiveId: (perspectiveId) =>
1339	      set(() => {
1340	        try {
1341	          localStorage.setItem('bim.perspective', perspectiveId);
1342	        } catch {
1343	          /* noop */
1344	        }
1345	        return { perspectiveId };
1346	      }),
1347	
1348	    setPlanPresentationPreset: (planPresentationPreset) =>
1349	      set(() => {
1350	        try {
1351	          localStorage.setItem('bim.planPresentation', planPresentationPreset);
1352	        } catch {
1353	          /* noop */
1354	        }
1355	        return { planPresentationPreset };
1356	      }),
1357	
1358	    activatePlanView: (planViewElementId) => {
1359	      if (!planViewElementId) {
1360	        set({ activePlanViewId: undefined });
1361	        return;
1362	      }
1363	      const el = get().elementsById[planViewElementId];
1364	      if (!el || el.kind !== 'plan_view') return;
1365	      const preset = el.planPresentation ?? 'default';
1366	      const normalized: PlanPresentationPreset =
1367	        preset === 'opening_focus' || preset === 'room_scheme' ? preset : 'default';
1368	      try {
1369	        localStorage.setItem('bim.planPresentation', normalized);
1370	      } catch {
1371	        /* noop */
1372	      }
1373	      set({
1374	        activePlanViewId: planViewElementId,
1375	        activeViewpointId: undefined,
1376	        activeLevelId: el.levelId,
1377	        planPresentationPreset: normalized,
1378	        viewerMode: 'plan_canvas',
1379	      });
1380	    },
1381	
1382	    setActiveViewpointId: (viewpointElementId) => set({ activeViewpointId: viewpointElementId }),
1383	
1384	    setViewerClipElevMm: (viewerClipElevMm) => set({ viewerClipElevMm }),
1385	
1386	    setViewerClipFloorElevMm: (viewerClipFloorElevMm) => set({ viewerClipFloorElevMm }),
1387	
1388	    setPlanProjectionPrimitives: (planProjectionPrimitives) =>
1389	      planProjectionPrimitives === null
1390	        ? set({ planProjectionPrimitives: null, planRoomSchemeWireReadout: null })
1391	        : set({ planProjectionPrimitives }),
1392	
1393	    setPlanRoomSchemeWireReadout: (planRoomSchemeWireReadout) => set({ planRoomSchemeWireReadout }),
1394	
1395	    setScheduleBudgetHydration: (scheduleBudgetHydration) => set({ scheduleBudgetHydration }),
1396	
1397	    toggleViewerCategoryHidden: (semanticKind) =>
1398	      set(() => {
1399	        const prior = get().viewerCategoryHidden[semanticKind];
1400	        const next = { ...get().viewerCategoryHidden, [semanticKind]: !prior };
1401	        return { viewerCategoryHidden: next };
1402	      }),
1403	
1404	    applyOrbitViewpointPreset: (opts) =>
1405	      set((state) => {
1406	        const LayerKeys = ['wall', 'floor', 'roof', 'stair', 'door', 'window', 'room'] as const;
1407	        let viewerClipElevMm = state.viewerClipElevMm;
1408	        if ('capElevMm' in opts) {
1409	          const v = opts.capElevMm;
1410	          viewerClipElevMm =
1411	            v !== undefined && v !== null && typeof v === 'number' && Number.isFinite(v) ? v : null;
1412	        }
1413	        let viewerClipFloorElevMm = state.viewerClipFloorElevMm;
1414	        if ('floorElevMm' in opts) {
1415	          const v = opts.floorElevMm;
1416	          viewerClipFloorElevMm =
1417	            v !== undefined && v !== null && typeof v === 'number' && Number.isFinite(v) ? v : null;
1418	        }
1419	        let viewerCategoryHidden = state.viewerCategoryHidden;
1420	        if (opts.hideSemanticKinds !== undefined) {
1421	          const hid = new Set(opts.hideSemanticKinds);
1422	          viewerCategoryHidden = { ...state.viewerCategoryHidden };
1423	          for (const lk of LayerKeys) {
1424	            viewerCategoryHidden[lk] = hid.has(lk);
1425	          }
1426	        }
1427	        return {
1428	          viewerClipElevMm,
1429	          viewerClipFloorElevMm,
1430	          viewerCategoryHidden,
1431	        };
1432	      }),
1433	
1434	    setOrbitCameraFromViewpointMm: ({ position, target, up }) =>
1435	      set((state) => ({
1436	        orbitCameraPoseMm: { position, target, up },
1437	        orbitCameraNonce: state.orbitCameraNonce + 1,
1438	      })),
1439	
1440	    setActivity: (e) => set({ activityEvents: e }),
1441	
1442	    setIdentity: (userId, userDisplayName, peerId) =>
1443	      set(() => {
1444	        try {
1445	          sessionStorage.setItem('bim.userId', userId);
1446	
1447	          sessionStorage.setItem('bim.displayName', userDisplayName);
1448	
1449	          sessionStorage.setItem('bim.peerId', peerId);
1450	        } catch {
1451	          /* noop */
1452	        }
1453	
1454	        return { userId, userDisplayName: userDisplayName, peerId };
1455	      }),
1456	
1457	    vvDialogOpen: false,
1458	
1459	    openVVDialog: () => set({ vvDialogOpen: true }),
1460	
1461	    closeVVDialog: () => set({ vvDialogOpen: false }),
1462	
1463	    setCategoryOverride: (planViewId, categoryKey, override) => {
1464	      const { elementsById } = get();
1465	      const pv = elementsById[planViewId];
1466	      if (!pv || pv.kind !== 'plan_view') return;
1467	      const prevOverrides =
1468	        (pv.categoryOverrides as import('./storeTypes').CategoryOverrides) ?? {};
1469	      const newOverrides = { ...prevOverrides, [categoryKey]: override };
1470	      set({
1471	        elementsById: {
1472	          ...elementsById,
1473	          [planViewId]: { ...pv, categoryOverrides: newOverrides },
1474	        },
1475	      });
1476	    },
1477	  };
