7	} from '@bim-ai/core';
8	
9	import type { PlanAnnotationHintsResolved, PlanGraphicHintsResolved } from './planProjectionWire';
10	import type { PlanPresentationPreset } from './symbology';
11	
12	export type PlanSemanticKind =
13	  | 'wall'
14	  | 'floor'
15	  | 'roof'
16	  | 'room'
17	  | 'door'
18	  | 'window'
19	  | 'stair'
20	  | 'grid_line'
21	  | 'room_separation'
22	  | 'dimension';
