24	/** Map schedule / authoring labels to semantic drawing kinds consumed by symbology. */
25	
26	export function canonHiddenCategory(cat: string): PlanSemanticKind | undefined {
27	  const raw = cat.trim().toLowerCase();
28	
29	  const table: Record<string, PlanSemanticKind> = {
30	    walls: 'wall',
31	    wall: 'wall',
32	    floors: 'floor',
33	    slabs: 'floor',
34	    slab: 'floor',
35	    floor: 'floor',
36	    roofs: 'roof',
37	    roof: 'roof',
38	    rooms: 'room',
39	    room: 'room',
40	    doors: 'door',
41	    door: 'door',
42	    windows: 'window',
43	    window: 'window',
44	    stairs: 'stair',
45	    stair: 'stair',
46	    grids: 'grid_line',
47	    grid: 'grid_line',
48	    gridlines: 'grid_line',
49	    grid_line: 'grid_line',
50	    'grid-lines': 'grid_line',
51	    'room separation': 'room_separation',
52	    'room separation line': 'room_separation',
53	    'room separators': 'room_separation',
54	    'room separators line': 'room_separation',
55	    room_separation: 'room_separation',
56	    room_separator: 'room_separation',
57	    'room separating': 'room_separation',
58	    'room-separation': 'room_separation',
59	    'room-separations': 'room_separation',
60	    dimensions: 'dimension',
61	    dimension: 'dimension',
62	  };
63	
64	  return table[raw] ?? undefined;
65	}
66	
67	export type PlanViewResolvedDisplay = {
68	  /** Active authoring level derived from pinned plan_view (or fallback). */
69	  activeLevelId?: string;
70	  presentation: PlanPresentationPreset;
71	  hiddenSemanticKinds: ReadonlySet<PlanSemanticKind>;
72	  planViewElementId?: string;
73	};
74	
75	function mergeHiddenFromLabels(labels: Iterable<string>, into: Set<PlanSemanticKind>) {
76	  for (const lab of labels) {
77	    const k = canonHiddenCategory(lab);
78	    if (k) into.add(k);
79	  }
80	}
81	
82	/**
83	 * Computes level, presentation preset, and per-category hides for PlanCanvas symbology.
84	 * When a plan_view is active, presentation and pinned level come from that element first.
85	 */
86	
87	export function resolvePlanViewDisplay(
88	  elementsById: Record<string, Element>,
89	  activePlanViewId: string | undefined,
90	  fallbackLevelId: string | undefined,
91	  globalPresentation: PlanPresentationPreset,
92	): PlanViewResolvedDisplay {
93	  const hidden = new Set<PlanSemanticKind>();
94	
95	  if (!activePlanViewId) {
96	    return {
97	      activeLevelId: fallbackLevelId,
98	      presentation: globalPresentation,
99	      hiddenSemanticKinds: hidden,
100	    };
101	  }
102	
103	  const el = elementsById[activePlanViewId];
104	
105	  if (!el || el.kind !== 'plan_view') {
106	    return {
107	      activeLevelId: fallbackLevelId,
108	      presentation: globalPresentation,
109	      hiddenSemanticKinds: hidden,
110	    };
111	  }
112	
113	  mergeHiddenFromLabels(el.categoriesHidden ?? [], hidden);
114	
115	  const tmplId = el.viewTemplateId;
116	  if (tmplId) {
117	    const tmpl = elementsById[tmplId];
118	    if (tmpl && tmpl.kind === 'view_template') {
119	      mergeHiddenFromLabels(tmpl.hiddenCategories ?? [], hidden);
120	    }
121	  }
122	
123	  const presRaw = el.planPresentation ?? 'default';
124	  const presentation: PlanPresentationPreset =
125	    presRaw === 'opening_focus' || presRaw === 'room_scheme' ? presRaw : 'default';
126	
127	  return {
128	    activeLevelId: el.levelId,
129	    presentation,
130	    hiddenSemanticKinds: hidden,
131	    planViewElementId: el.id,
132	  };
133	}
134	
135	const PLAN_DETAIL_LINE_WEIGHT_FACTOR: Record<string, number> = {
136	  coarse: 0.88,
137	  medium: 1.0,
138	  fine: 1.14,
139	};
140	
141	function presentationLineWeightBase(presentation: PlanPresentationPreset): number {
142	  if (presentation === 'opening_focus') return 1.18;
143	  if (presentation === 'room_scheme') return 0.92;
144	  return 1.0;
145	}
146	
147	/** Client fallback when wire omits hints — mirrors server `_plan_graphic_hints_for_pinned_view`. */
148	
149	export function resolvePlanGraphicHints(
150	  elementsById: Record<string, Element>,
151	  activePlanViewId: string | undefined,
152	): PlanGraphicHintsResolved | null {
153	  if (!activePlanViewId) return null;
154	  const el = elementsById[activePlanViewId];
155	  if (!el || el.kind !== 'plan_view') return null;
156	
157	  let tmpl: Extract<Element, { kind: 'view_template' }> | undefined;
158	  const tmplId = el.viewTemplateId;
159	  if (tmplId) {
160	    const t = elementsById[tmplId];
161	    if (t?.kind === 'view_template') tmpl = t;
162	  }
163	
164	  let detail: string;
165	  if (el.planDetailLevel) {
166	    detail = el.planDetailLevel;
167	  } else if (tmpl?.planDetailLevel) {
168	    detail = tmpl.planDetailLevel;
169	  } else {
170	    detail = 'medium';
171	  }
172	  if (PLAN_DETAIL_LINE_WEIGHT_FACTOR[detail] === undefined) detail = 'medium';
173	
174	  let fill: number;
175	  if (el.planRoomFillOpacityScale != null && Number.isFinite(el.planRoomFillOpacityScale)) {
176	    fill = Math.max(0, Math.min(1, el.planRoomFillOpacityScale));
177	  } else if (
178	    tmpl?.planRoomFillOpacityScale != null &&
179	    Number.isFinite(tmpl.planRoomFillOpacityScale)
180	  ) {
181	    fill = Math.max(0, Math.min(1, tmpl.planRoomFillOpacityScale));
182	  } else {
183	    fill = 1.0;
184	  }
185	
186	  const presRaw = el.planPresentation ?? 'default';
187	  const presentation: PlanPresentationPreset =
188	    presRaw === 'opening_focus' || presRaw === 'room_scheme' ? presRaw : 'default';
189	  const lw = presentationLineWeightBase(presentation) * PLAN_DETAIL_LINE_WEIGHT_FACTOR[detail]!;
190	
191	  return {
192	    detailLevel: detail,
193	    lineWeightScale: Math.round(lw * 10000) / 10000,
194	    roomFillOpacityScale: Math.round(fill * 10000) / 10000,
195	  };
196	}
197	
198	export const PLAN_CATEGORY_GRAPHIC_KEYS: readonly PlanCategoryGraphicCategoryKey[] = [
199	  'wall',
200	  'floor',
201	  'roof',
202	  'room',
203	  'door',
204	  'window',
205	  'stair',
206	  'grid_line',
207	  'room_separation',
208	  'dimension',
209	];
