211	export type ResolvedPlanCategoryGraphic = {
212	  lineWeightFactor: number;
213	  linePatternToken: PlanLinePatternToken;
214	  lineWeightSource: 'default' | 'template' | 'plan_view';
215	  linePatternSource: 'default' | 'template' | 'plan_view';
216	  lineWeightIsDefaulted: boolean;
217	  linePatternIsDefaulted: boolean;
218	  visible: boolean;
219	  lineColor: string | null;
220	};
221	
222	function categoryGraphicsRowMap(rows: PlanCategoryGraphicRow[] | undefined) {
223	  return new Map((rows ?? []).map((r) => [r.categoryKey, r]));
224	}
225	
226	/** Client merge mirror of server `resolve_plan_category_graphics_for_pinned_view`. */
227	
228	export function resolvePlanCategoryGraphics(
229	  elementsById: Record<string, Element>,
230	  activePlanViewId: string | undefined,
231	): Record<PlanCategoryGraphicCategoryKey, ResolvedPlanCategoryGraphic> | null {
232	  if (!activePlanViewId) return null;
233	  const el = elementsById[activePlanViewId];
234	  if (!el || el.kind !== 'plan_view') return null;
235	
236	  let tmpl: Extract<Element, { kind: 'view_template' }> | undefined;
237	  if (el.viewTemplateId) {
238	    const t = elementsById[el.viewTemplateId];
239	    if (t?.kind === 'view_template') tmpl = t;
240	  }
241	  const tmplMap = categoryGraphicsRowMap(tmpl?.planCategoryGraphics);
242	  const pvMap = categoryGraphicsRowMap(el.planCategoryGraphics);
243	  const out = {} as Record<PlanCategoryGraphicCategoryKey, ResolvedPlanCategoryGraphic>;
244	  for (const key of PLAN_CATEGORY_GRAPHIC_KEYS) {
245	    let f = 1;
246	    let pat: PlanLinePatternToken = key === 'room_separation' ? 'dash_short' : 'solid';
247	    let wSrc: 'default' | 'template' | 'plan_view' = 'default';
248	    let pSrc: 'default' | 'template' | 'plan_view' = 'default';
249	    let wDef = true;
250	    let pDef = true;
251	    const tr = tmplMap.get(key);
252	    if (tr) {
253	      if (tr.lineWeightFactor != null && Number.isFinite(tr.lineWeightFactor)) {
254	        f = tr.lineWeightFactor;
255	        wSrc = 'template';
256	        wDef = false;
257	      }
258	      if (tr.linePatternToken) {
259	        pat = tr.linePatternToken;
260	        pSrc = 'template';
261	        pDef = false;
262	      }
263	    }
264	    const pr = pvMap.get(key);
265	    if (pr) {
266	      if (pr.lineWeightFactor != null && Number.isFinite(pr.lineWeightFactor)) {
267	        f = pr.lineWeightFactor;
268	        wSrc = 'plan_view';
269	        wDef = false;
270	      }
271	      if (pr.linePatternToken) {
272	        pat = pr.linePatternToken;
273	        pSrc = 'plan_view';
274	        pDef = false;
275	      }
276	    }
277	    out[key] = {
278	      lineWeightFactor: Math.round(f * 10000) / 10000,
279	      linePatternToken: pat,
280	      lineWeightSource: wSrc,
281	      linePatternSource: pSrc,
282	      lineWeightIsDefaulted: wDef,
283	      linePatternIsDefaulted: pDef,
284	      visible: true,
285	      lineColor: null,
286	    };
287	  }
288	  // Apply per-view category overrides (VV dialog).
289	  const pvEl = elementsById[activePlanViewId];
290	  if (pvEl?.kind === 'plan_view') {
291	    const overrides = (pvEl.categoryOverrides ?? {}) as Record<
292	      string,
293	      {
294	        visible?: boolean;
295	        projection?: { lineWeightFactor?: number; lineColor?: string | null };
296	      }
297	    >;
298	    for (const [catKey, ovr] of Object.entries(overrides)) {
299	      const k = catKey as PlanCategoryGraphicCategoryKey;
300	      if (!out[k]) continue;
301	      if (ovr.visible === false) {
302	        out[k].visible = false;
303	      }
304	      if (ovr.projection?.lineWeightFactor != null) {
305	        out[k].lineWeightFactor = ovr.projection.lineWeightFactor;
306	      }
307	      if (ovr.projection?.lineColor != null) {
308	        out[k].lineColor = ovr.projection.lineColor;
309	      }
310	    }
311	  }
312	  return out;
313	}
