315	/** Mirrors server `_plan_annotation_hints_for_pinned_view` until wire payloads arrive. */
316	
317	export function resolvePlanAnnotationHints(
318	  elementsById: Record<string, Element>,
319	  activePlanViewId: string | undefined,
320	): PlanAnnotationHintsResolved {
321	  const off = (): PlanAnnotationHintsResolved => ({
322	    openingTagsVisible: false,
323	    roomLabelsVisible: false,
324	  });
325	  if (!activePlanViewId) return off();
326	  const el = elementsById[activePlanViewId];
327	  if (!el || el.kind !== 'plan_view') return off();
328	
329	  let tmpl: Extract<Element, { kind: 'view_template' }> | undefined;
330	  if (el.viewTemplateId) {
331	    const t = elementsById[el.viewTemplateId];
332	    if (t?.kind === 'view_template') tmpl = t;
333	  }
334	
335	  let openingTagsVisible: boolean;
336	  if (el.planShowOpeningTags !== undefined) {
337	    openingTagsVisible = el.planShowOpeningTags;
338	  } else {
339	    openingTagsVisible = tmpl?.planShowOpeningTags ?? false;
340	  }
341	
342	  let roomLabelsVisible: boolean;
343	  if (el.planShowRoomLabels !== undefined) {
344	    roomLabelsVisible = el.planShowRoomLabels;
345	  } else {
346	    roomLabelsVisible = tmpl?.planShowRoomLabels ?? false;
347	  }
348	
349	  return { openingTagsVisible, roomLabelsVisible };
350	}
351	
352	export const BUILTIN_PLAN_TAG_OPENING_ID = 'builtin-plan-tag-opening';
353	export const BUILTIN_PLAN_TAG_ROOM_ID = 'builtin-plan-tag-room';
354	
355	export type PlanTagStyleLane = PlanTagTarget;
356	
357	export type ResolvedPlanTagStyleLane = {
358	  resolvedStyleId: string;
359	  resolvedStyleName: string;
360	  source: 'plan_view' | 'view_template' | 'builtin';
361	  textSizePt: number;
362	};
363	
364	function builtinPlanTagLane(lane: PlanTagStyleLane): ResolvedPlanTagStyleLane {
365	  return {
366	    resolvedStyleId: lane === 'opening' ? BUILTIN_PLAN_TAG_OPENING_ID : BUILTIN_PLAN_TAG_ROOM_ID,
367	    resolvedStyleName: 'Builtin',
368	    source: 'builtin',
369	    textSizePt: 10,
370	  };
371	}
372	
373	function resolvedPlanTagFromRef(
374	  elementsById: Record<string, Element>,
375	  ref: string | null | undefined,
376	  lane: PlanTagStyleLane,
377	  source: ResolvedPlanTagStyleLane['source'],
378	): ResolvedPlanTagStyleLane {
379	  if (!ref) return builtinPlanTagLane(lane);
380	  const style = elementsById[ref];
381	  if (style?.kind !== 'plan_tag_style' || style.tagTarget !== lane) {
382	    return builtinPlanTagLane(lane);
383	  }
384	  return {
385	    resolvedStyleId: style.id,
386	    resolvedStyleName: style.name,
387	    source,
388	    textSizePt: style.textSizePt,
389	  };
390	}
391	
392	/** Mirrors server `plan_view` → `view_template` → builtin precedence (WP-C02). */
393	
394	export function resolvePlanTagStyleLane(
395	  elementsById: Record<string, Element>,
396	  planViewId: string | undefined,
397	  lane: PlanTagStyleLane,
398	): ResolvedPlanTagStyleLane {
399	  if (!planViewId) return builtinPlanTagLane(lane);
400	  const pv = elementsById[planViewId];
401	  if (!pv || pv.kind !== 'plan_view') return builtinPlanTagLane(lane);
402	
403	  const pvRef = lane === 'opening' ? pv.planOpeningTagStyleId : pv.planRoomTagStyleId;
