  const pvRoomRef = el.planRoomTagStyleId;
  const roomStored = pvRoomRef
    ? formatPlanTagStyleMatrixCell(
        resolvedPlanTagFromRef(elementsById, pvRoomRef, 'room', 'plan_view'),
